9	######################################################
10	puts "
11	######################################################
12	#  Export Flow                                       #
13	#                                                    #
14	#  Fix process antennas, add fillers & metal fill    #
15	#  Output design data.                               #
16	#  Control vars defined in flow_variables.tcl        #
17	#                                                    #
18	######################################################
19	"
20	
21	config_shell -echo_script false
22	fk_msg -set_prompt NRF
23	
24	###Sourcing design and technology variables
25	source flow_variables.tcl
26	source scr/kit_utils.tcl
27	load_utils -name nrf_utils 
28	load_utils -name save_vars
29	load_utils -name db_utils
30	
31	set MGC_flowStage export
32	
33	# Read DB
34	if {![string length [get_top_partition]]} {
35	    if { [file exists dbs/libs.db] } {
36		# Split db is used
37	        if { [file isfile dbs/libs.db] } {
38	            # Old DB -- Convert to 2.5
39	            util::update_split_db -lib_db dbs/libs.db -design_db dbs/route.db
40	        } else {
41		    read_db -file dbs/libs.db
42		    read_db -file dbs/route.db
43	        }
44		config_default_value -command write_db -argument data -value design
45	    } else {
46	        if { [file isfile dbs/route.db] } {
47	            # Old DB -- Convert to 2.5
48	            util::update_full_db -design_db dbs/route.db
49	        } else {
50		    read_db -file dbs/route.db
51	        }
52	    }
53	}
54	
55	set num_errors [nrf_utils::check_flow_variables $MGC_flowStage]
56	if { $num_errors > 0 } {
57	    fk_msg -type error "Please fix all errors to continue execution"
58	    return -code error
59	}
60	util::save_vars
61	
62	lpp::create_cell_edge_constraints
63	
64	## Fix Antenna
65	set MGC_fix_antenna true             ; # Mandatory to review : true|false
66	
67	if { [file exists nrf_customization.tcl] } {
68	    source nrf_customization.tcl
69	}
70	
71	if {$MGC_fix_antenna eq true} {
72	    check_antenna -cpus $MGC_cpus
73	    fix_antenna -method jumper -cpus $MGC_cpus
74	
75	    if {$MGC_fix_antenna_use_diodes eq true} {
76		if {$MGC_fix_antenna_diodes != ""} {
77		    config_antenna -diodes $MGC_fix_antenna_diodes
78		}
79		fix_antenna -method diode -finish all
80	    }
81	}
82	
83	## Check if design is DRC clean before starting chip finishing
84	set MGC_num_drc_errors_threshold 100    ; # If number of DRC errors exceeds this threshold the chip finishing steps will not be performed
85	check_drc
86	set num0 [llength [get_objects -type error -filter @category==drc -quiet true]]
87	set skip_chip_finishing false
88	if { $num0 > $MGC_num_drc_errors_threshold } {
89	    fk_msg -type info "Number of DRC (including antenna) errors is too high ($num0 > $MGC_num_drc_errors_threshold). Chip finishing steps will be skipped \n"
90	    set skip_chip_finishing true
91	}
92	
93	## Place Filler
94	set MGC_insert_filler_cells true     ; # true|false
95	
96	if { $skip_chip_finishing == false && $MGC_insert_filler_cells eq true} {
97	    # only needed for advanced nodes 
98	    #config_place_detail -name honor_lib_cell_edge_spacing -value true
99	    set_property -objects [get_lib_cells -filter @is_filler] -name is_dont_use -value true
100	    if {[llength $MGC_filler_lib_cells] == 0} {
101	        set lc_list [get_lib_cells -filter @is_filler]
102	        if {[llength $lc_list] == 0} {
103		    fk_msg -type error "Could not find any lib cells marked as filler cells.  No fillers inserted.\n"
104	        } else {
105	            set_property -objects $lc_list -name is_dont_use -value false
106		    fk_msg -type info "Placing filler cells using all lib cells marked as fillers: $lc_list\n"
107		    place_filler_cells -cpus $MGC_cpus -lib_cells $lc_list -respect_blockages $MGC_filler_respect_blockages
108	        }
109	    } elseif {[llength $MGC_filler_lib_cells] == 1} {
110	        set lc_list [get_lib_cells -filter @is_filler -pattern $MGC_filler_lib_cells]
111	        if {[llength $lc_list] == 0} {
112		    fk_msg -type error "Could not find any filler lib cells matching pattern $MGC_filler_lib_cells.  No fillers inserted.\n"
113	        } else {
114		    set_property -objects $lc_list -name is_dont_use -value false
115		    fk_msg -type info "Placing filler cells using lib cells: $lc_list\n"
116		    place_filler_cells -cpus $MGC_cpus -lib_cells $lc_list -respect_blockages $MGC_filler_respect_blockages
117	        }
118	    } else {
119	        set lc_string [join $MGC_filler_lib_cells]
120	        set tempvar ""
121	        if {[string is integer -strict [lindex $lc_string 1]]} {
122	            for {set x 0} {$x < [llength $lc_string]} {incr x 2} {
123	              set fcpattern [lindex $lc_string $x]
124	              set fcpercent [lindex $lc_string $x+1]
125	              lappend tempvar "$fcpattern $fcpercent"
126	            }
127	            set MGC_filler_lib_cells $tempvar
128		    # Place filler cells by using the percentage-based algorithm
129		    set fill_groups {}
130		    foreach filler_group $MGC_filler_lib_cells {
131		        set filler_libcells [lindex $filler_group 0]
132		        set filler_percentage [lindex $filler_group 1]
133		        set filler_groupname [regsub -all {[*?]} $filler_libcells ""]
134		        set_property -objects [get_lib_cells -filter is_filler -pattern $filler_libcells] -name is_dont_use -value false
135		        create_filler_set -name FS_$filler_groupname -lib_cells [get_lib_cells -filter is_filler -pattern $filler_libcells]
136		        lappend fill_groups FS_$filler_groupname $filler_percentage
137		    }
138	            fk_msg -type info "Placing filler cells using filler sets."
139	            report_filler_sets
140	            puts "Filler set percentages:"
141	            for {set x 0} {$x < [llength $fill_groups]} {incr x 2} {
142	                puts "\t[lindex $fill_groups $x] = [lindex $fill_groups $x+1]%"
143	            }
144	            puts ""
145		    place_filler_cells -filler_set_prefix true -filler_set_percentages $fill_groups -cpus $MGC_cpus -respect_blockages $MGC_filler_respect_blockages
146	        } else {
147	            set lc_list [get_lib_cells -filter @is_filler -pattern $MGC_filler_lib_cells]
148	            if {[llength $lc_list] == 0} {
149	                fk_msg -type error "Could not find any filler lib cells matching pattern $MGC_filler_lib_cells.  No fillers inserted.\n"
150	            } else {
151	                set_property -objects $lc_list -name is_dont_use -value false
152	                fk_msg -type info "Placing filler cells using lib cells: $lc_list\n"
153	                place_filler_cells -cpus $MGC_cpus -lib_cells $lc_list -respect_blockages $MGC_filler_respect_blockages
154	            }
155	        }
156	    }
157	    
158	    ## Check for unfilled gaps.  
159	    ## This has a dependency on how fill was inserted under blockages.
160	    fk_msg -type info "Checking for unfilled gaps after filler cell insertion"
161	    if { $MGC_filler_respect_blockages == "hard" } {
162	            check_unfilled_gaps -include_gaps_under_blockage false
163	       } elseif { $MGC_filler_respect_blockages == "all" } {
164	            check_unfilled_gaps -include_gaps_under_blockage false
165	       } elseif { $MGC_filler_respect_blockages == "none" } {
166	            check_unfilled_gaps -include_gaps_under_blockage true
167	       }
168	         
169	    ## Check for any new DRC issues and fix them
170	    check_drc
171	    set num1 [llength [get_objects -type error -filter @category==drc]]
172	    if { $num1 } {
173		if { $num1 > $num0 } {
174		    fk_msg -type info "Number of DRC errors increased after filler cell insertion ($num1 > $num0). Running DRC clean-up \n"
175		} else {
176		    fk_msg -type info "Running DRC clean-up for remaining $num1 errors.\n"
177		}
178		clean_drc
179		run_route_timing -mode repair -cpus $MGC_cpus -user_params "-drc_effort high -drc_accept number -dp_local_effort high"
180		check_drc
181		set num2 [llength [get_objects -type error -filter @category==drc]]
182		if { $num2 } {
183		    fk_msg -type info "$num2 DRC errors remain.\n"
184		}
185	    }
186	}
187	## Insert Metal Fill
188	if { $skip_chip_finishing == false && $MGC_skip_metal_fill == false} {
189	     fk_msg -type info "Inserting metal fill"
190	     insert_metal_fill
191	}
192	
193	## Write out data
194	set design [current_design]
195	set dataDir output
196	
197	if { [info exists MGC_tanner_flow] && $MGC_tanner_flow eq "true"} {
198	    # Write output data to EXPORT directory
199	    write_verilog -file results/[current_design].v -bus_aware true
200	    write_def -skip regions -all_vias -db_units 1000 -file results/routed.def -prefix_special_characters false
201	    set corners [get_corners -filter enable]
202	    set modes [get_modes -filter enable]
203	    foreach_in_collection el $corners {
204		foreach el1 $modes {
205		    write_sdf -corner $el -mode $el1 -file ./results/SDF_[current_design]_${el}_${el1}.sdf -skip_backslash true
206		}
207	    }
208	    # Exporting SPEF
209	    foreach el $corners {
210		write_spef -corner $el  -file ./results/SPEF_[current_design]_${el}.spef -coupling
211	    }
212	} else {
213	    write_verilog -file $dataDir/${design}.v.gz
214	    write_def -file $dataDir/${design}.def.gz
215	    write_lef -file $dataDir/${design}.lef.gz -lib_cells [get_lib_cells -of_objects [get_top_partition]]
216	}
217	
218	# Export GDS
219	#we might need resolution 5.0:
220	#config_write_stream -resolution 5.0
221	if { $MGC_gds_layer_map_file != "" } {
222	    source $MGC_gds_layer_map_file
223	    write_stream -format gds -file $dataDir/${design}.gds
224	} elseif { $MGC_gds_layer_map_file == "" } {
225	    fk_msg -type warning "No GDS layer-map file specified in flow variable MGC_gds_layer_map_file.  GDS will not be written"
226	} 
227	
228	# Save db
229	if { [file exists dbs/libs.db] } {
230	    ## split_db is true
231	    write_db -data design -file dbs/export.db
232	} else {
233	    write_db -data all -file dbs/export.db
234	}
235	nrf_utils::write_reports $MGC_flowStage reports 100
236	
237	# Propagate power and grounds and output power netlist
238	
239	if { [info exists MGC_no_exit] && $MGC_no_exit eq "true" } {
240	    fk_msg -type info "Because Nitro is not being exited, supply nets are not propagated and power netlist is not output by default.\n"
241	} else {
242	    propagate_power_and_ground_nets
243	    write_verilog -file $dataDir/${design}.power.v.gz -power true -well_connections true
244	#    exit
245	}
246	
